const path = require("path");
const fs = require("fs");

const problemsFile = path.resolve(__dirname, "../../data/problems.json");

let problemsData = null;

function loadProblemsData() {
  if (!problemsData) {
    const raw = fs.readFileSync(problemsFile, "utf8");
    problemsData = JSON.parse(raw);
  }
  return problemsData;
}

/**
 * Get problem detail by problemId including aggregated component statistics.
 * @param {string} problemId
 * @returns {object|null} problem detail with component stats or null if not found
 */
function getProblemDetail(problemId) {
  const problems = loadProblemsData();
  const problem = problems.find(p => p.id === problemId);
  if (!problem) {
    return null;
  }

  // Aggregate component statistics
  // language counts, status counts, max points
  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  if (Array.isArray(problem.components)) {
    for (const comp of problem.components) {
      // Language count
      if (comp.language) {
        languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
      }
      // Status count
      if (comp.status) {
        statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
      }
      // Max points
      if (typeof comp.points === "number" && comp.points > maxPoints) {
        maxPoints = comp.points;
      }
    }
  }

  // Return problem detail with aggregated stats
  return {
    ...problem,
    componentStats: {
      languageCounts,
      statusCounts,
      maxPoints
    }
  };
}

module.exports = {
  getProblemDetail
};
